32	// ChildBeadSpec describes one child bead produced by the splitter prompt.
33	type ChildBeadSpec struct {
34		Title        string   `json:"title"`
35		Description  string   `json:"description,omitempty"`
36		Acceptance   string   `json:"acceptance,omitempty"`
37		Labels       []string `json:"labels,omitempty"`
38		SpecID       string   `json:"spec_id,omitempty"`
39		InScopeFiles []string `json:"in_scope_files,omitempty"`
