42	// TriageGate is called for each candidate bead between RoutePreflight and Claim.
43	// Returns (true, nil) when the bead is atomic and should proceed to Claim.
44	// Returns (false, nil) when the gate handled the bead (decomposed or surfaced
45	// for human triage). Returns (false, err) on a gate error — the loop logs the
46	// error and skips the bead without claiming.
47	type TriageGate func(ctx context.Context, candidate bead.Bead) (shouldClaim bool, err error)
48	
49	// ComplexityClassifier classifies a bead as atomic, decomposable, or ambiguous.
50	// Returns the classification string, a confidence in [0,1], and a human-readable
51	// reasoning string.
52	type ComplexityClassifier func(ctx context.Context, b bead.Bead) (classification string, confidence float64, reasoning string, err error)
53	
54	// BeadSplitter decomposes a decomposable bead into child specs.
55	type BeadSplitter func(ctx context.Context, b bead.Bead) (children []ChildBeadSpec, rationale string, err error)
