57	// TriageStore is the store interface required by the triage gate for child
58	// filing and parent mutation. *bead.Store satisfies this interface.
59	type TriageStore interface {
60		Create(b *bead.Bead) error
61		Update(id string, fn func(*bead.Bead)) error
62		AppendEvent(id string, ev bead.BeadEvent) error
63	}
