170	// triageDepth reads the current decomposition depth from a bead's Extra field.
171	// JSON numbers unmarshal as float64; the switch handles all common numeric types.
172	func triageDepth(b bead.Bead) int {
173		if b.Extra == nil {
174			return 0
175		}
176		switch v := b.Extra[TriageDepthKey].(type) {
177		case int:
178			return v
179		case float64:
180			return int(v)
181		case int64:
182			return int(v)
183		case json.Number:
184			n, _ := v.Int64()
185			return int(n)
186		}
187		return 0
188	}
