259	// ACCoverageRate computes the fraction of unique AC tokens from the parent that
260	// appear in the combined AC text of the child specs. This is the string-overlap
261	// metric used by the TriagePrompts tests to assert >= 90% coverage after a split.
262	// Tokens shorter than 3 characters are ignored as stop-words.
263	func ACCoverageRate(parentAC string, children []ChildBeadSpec) float64 {
264		parentTokens := tokenizeAC(parentAC)
265		if len(parentTokens) == 0 {
266			return 1.0
267		}
268	
269		// Deduplicate parent tokens.
270		parentSet := make(map[string]bool, len(parentTokens))
271		for _, t := range parentTokens {
272			parentSet[t] = true
273		}
274	
275		var childBuilder strings.Builder
276		for _, c := range children {
277			childBuilder.WriteString(" ")
278			childBuilder.WriteString(c.Acceptance)
279		}
280		childTokens := tokenizeAC(childBuilder.String())
281		childSet := make(map[string]bool, len(childTokens))
282		for _, t := range childTokens {
283			childSet[t] = true
284		}
285	
286		covered := 0
287		for t := range parentSet {
288			if childSet[t] {
289				covered++
290			}
291		}
292		return float64(covered) / float64(len(parentSet))
293	}
294	
295	// tokenizeAC normalises and splits acceptance-criteria text into lowercase
296	// alphanumeric tokens of length >= 3 for the AC-coverage overlap metric.
297	func tokenizeAC(s string) []string {
298		var tokens []string
299		var cur strings.Builder
300		for _, r := range strings.ToLower(s) {
301			if (r >= 'a' && r <= 'z') || (r >= '0' && r <= '9') {
302				cur.WriteRune(r)
303			} else {
304				if cur.Len() >= 3 {
305					tokens = append(tokens, cur.String())
306				}
307				cur.Reset()
308			}
309		}
310		if cur.Len() >= 3 {
311			tokens = append(tokens, cur.String())
312		}
313		return tokens
314	}
