567	func (m *WorkerManager) runWorker(ctx context.Context, id, dir string, spec ExecuteLoopWorkerSpec, projectRoot string, handle *workerHandle, log io.Writer, eventSink io.WriteCloser, progressCh chan agent.ProgressEvent) {
568		if eventSink != nil {
569			defer eventSink.Close() //nolint:errcheck
570		}
571		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
572	
573		var worker *agent.ExecuteBeadWorker
574		if m.BeadWorkerFactory != nil {
575			worker = m.BeadWorkerFactory(store)
576		} else {
577			// Build an executor that calls agent.ExecuteBead in-process, then
578			// submits the result to the project's land coordinator. The
579			// coordinator (a single goroutine per projectRoot) serializes all
580			// target-ref writes for this project — this is the server-side
581			// implementation of the human-PR landing model. See ddx-8746d8a6
582			// for the rationale. Prior to this rewrite, runWorker never called
583			// LandBeadResult at all, so commits produced by server-managed
584			// workers were silently lost (ddx-e14efc58).
585			coordinator := m.LandCoordinators.Get(projectRoot)
586	
587			// singleTierAttempt runs one execution at a specific harness/model.
588			singleTierAttempt := func(ctx context.Context, beadID string, tier escalation.ModelTier, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
589				gitOps := &agent.RealGitOps{}
590				attemptProvider := spec.Provider
591				if resolvedProvider != "" {
592					attemptProvider = resolvedProvider
593				}
594				attemptRcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
595					Harness:           resolvedHarness,
596					Model:             resolvedModel,
597					Provider:          attemptProvider,
598					ModelRef:          spec.ModelRef,
599					Effort:            spec.Effort,
600					OpaquePassthrough: spec.OpaquePassthrough,
601				})
602				res, err := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
603					BeadEvents: bead.NewStore(filepath.Join(projectRoot, ".ddx")),
604				}, gitOps)
605				if err != nil && res == nil {
606					return agent.ExecuteBeadReport{}, err
607				}
608				if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
609					if landErr := evaluateGatesAndSubmit(projectRoot, res, gitOps, coordinator, landSafetyConfigFromConfig(projectRoot), log); landErr != nil && err == nil {
610						err = landErr
611					}
612				} else if res != nil && res.ResultRev == res.BaseRev {
613					res.Outcome = "no-changes"
614					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
615				} else if res != nil && res.ExitCode != 0 {
616					res.Outcome = "preserved"
617					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
618				}
619				// Safety net: commit any leftover evidence files that Land()
620				// did not pick up (e.g. HEAD was detached, or no land ran).
621				if res != nil && res.AttemptID != "" {
622					_ = agent.VerifyCleanWorktree(projectRoot, res.AttemptID)
623				}
624				if err != nil {
625					return agent.ExecuteBeadReport{}, err
626				}
627				tierStr := ""
628				if tier != "" {
629					tierStr = string(tier)
630				}
631				return agent.ExecuteBeadReport{
632					BeadID:             res.BeadID,
633					AttemptID:          res.AttemptID,
634					WorkerID:           res.WorkerID,
635					Harness:            res.Harness,
636					Provider:           res.Provider,
637					Model:              res.Model,
638					ActualPower:        res.ActualPower,
639					Tier:               tierStr,
640					Status:             res.Status,
641					Detail:             res.Detail,
642					SessionID:          res.SessionID,
643					BaseRev:            res.BaseRev,
644					ResultRev:          res.ResultRev,
645					PreserveRef:        res.PreserveRef,
646					NoChangesRationale: res.NoChangesRationale,
647					CostUSD:            res.CostUSD,
648					DurationMS:         int64(res.DurationMS),
649				}, nil
650			}
651	
652			// Cost-cap state for this worker run. Subscription / local providers do
653			// not contribute (see escalation.CountsTowardCostCap).
654			// TODO(ddx-785d02f7): expose maxCostUSD as a worker spec field
655			// once the spec config knob lands.
656			costCap := escalation.NewCostCapTracker(escalation.DefaultMaxCostUSD, func(harnessName string) bool {
657				svc, svcErr := agent.NewServiceFromWorkDir(projectRoot)
658				if svcErr != nil {
659					return true
660				}
661				infos, err := svc.ListHarnesses(context.Background())
662				if err != nil {
663					return true
664				}
665				for _, h := range infos {
666					if h.Name == harnessName {
667						return escalation.CountsTowardCostCap(h.IsLocal, h.IsSubscription, h.CostClass)
668					}
669				}
670				return true
671			})
672			accumulateBilledCost := func(report agent.ExecuteBeadReport) {
673				costCap.Add(report.Harness, report.CostUSD)
674			}
675			costCapTripped := func() (agent.ExecuteBeadReport, bool) {
676				detail, tripped := costCap.Tripped()
677				if !tripped {
678					return agent.ExecuteBeadReport{}, false
679				}
680				return agent.ExecuteBeadReport{
681					Status: agent.ExecuteBeadStatusExecutionFailed,
682					Detail: detail,
683				}, true
684			}
685	
686			executor := agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
687				if cappedReport, capped := costCapTripped(); capped {
688					cappedReport.BeadID = beadID
689					return cappedReport, nil
690				}
691				report, err := singleTierAttempt(ctx, beadID, "", spec.Harness, spec.Provider, spec.Model)
692				if err == nil {
693					accumulateBilledCost(report)
694					if cappedReport, capped := costCapTripped(); capped {
695						cappedReport.BeadID = beadID
696						return cappedReport, nil
697					}
698				}
699				return report, err
700			})
701	
702			// Build post-merge reviewer. On-by-default unless NoReview is set in spec.
703			var reviewer agent.BeadReviewer
704			if !spec.NoReview {
705				reviewer = &agent.DefaultBeadReviewer{
706					ProjectRoot: projectRoot,
707					BeadStore:   bead.NewStore(filepath.Join(projectRoot, ".ddx")),
708					BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
709					Harness:     spec.ReviewHarness,
710					Model:       spec.ReviewModel,
711				}
712			}
713	
714			worker = &agent.ExecuteBeadWorker{
715				Store:    store,
716				Executor: executor,
717				Reviewer: reviewer,
718			}
719		}

